'use client'
// src/app/scanner/page.tsx - ESO Scanner powered by real Docker execution
import { useState, useEffect, useRef } from 'react'
import { esoScans, esoAuth } from '@/lib/eso/api'

interface ScanHistory { process_id:string; status:string; target?:string; risk_level?:string; findings_count?:number }

const GOALS = [
  'Scan for open ports and vulnerabilities',
  'Full web application security assessment',
  'Directory and endpoint discovery',
  'SQL injection and web vulnerability scan',
  'Technology fingerprinting and version detection',
]

const RISK_COLOR: Record<string,string> = {
  critical:'#ff3a5c', high:'#ff8c42', medium:'#ffd700', low:'#00aaff', none:'#64748b'
}

export default function ScannerPage() {
  const [target,    setTarget]    = useState('')
  const [goal,      setGoal]      = useState(GOALS[0])
  const [scanning,  setScanning]  = useState(false)
  const [processId, setProcessId] = useState<string|null>(null)
  const [status,    setStatus]    = useState<any>(null)
  const [history,   setHistory]   = useState<ScanHistory[]>([])
  const [error,     setError]     = useState('')
  const [logs,      setLogs]      = useState<string[]>([])
  const logRef  = useRef<HTMLDivElement>(null)
  const pollRef = useRef<ReturnType<typeof setInterval>|null>(null)

  useEffect(() => {
    esoScans.list().then((d:any) => setHistory((d.executions ?? []).slice(0,10))).catch(()=>{})
  }, [])

  useEffect(() => {
    if (!processId) return
    pollRef.current = setInterval(async () => {
      try {
        const s = await esoScans.status(processId)
        setStatus(s)
        if (s.current_task) setLogs(l => [...l.slice(-200), `[${s.status?.toUpperCase()}] ${s.current_task}`])
        if (['completed','failed','cancelled'].includes(s.status)) {
          clearInterval(pollRef.current!); setScanning(false)
          // refresh history
          esoScans.list().then((d:any) => setHistory((d.executions ?? []).slice(0,10))).catch(()=>{})
        }
      } catch {}
    }, 2500)
    return () => clearInterval(pollRef.current!)
  }, [processId])

  useEffect(() => {
    if (logRef.current) logRef.current.scrollTop = logRef.current.scrollHeight
  }, [logs])

  async function startScan() {
    if (!target.trim()) { setError('Enter a target'); return }
    setError(''); setLogs([]); setStatus(null); setScanning(true)
    try {
      const r = await esoScans.execute(goal, target.trim())
      setProcessId(r.process_id)
      setLogs([`Scan queued — ${r.process_id}`])
    } catch(e:any) { setError(e.message ?? 'Failed'); setScanning(false) }
  }

  return (
    <div className="p-5 space-y-4">
      <div>
        <h1 className="text-2xl font-black">Security <span className="text-accent">Scanner</span></h1>
        <p className="font-mono text-[11px] text-slate-500 mt-1">
          Real Docker-isolated execution — nmap · nuclei · gobuster · nikto · sqlmap
        </p>
      </div>

      {/* Config */}
      <div className="glass p-5 space-y-4">
        <div>
          <label className="font-mono text-[9px] uppercase tracking-widest text-slate-600 block mb-1.5">Target</label>
          <div className="flex gap-3">
            <input value={target} onChange={e=>setTarget(e.target.value)}
              onKeyDown={e=>e.key==='Enter'&&!scanning&&startScan()}
              placeholder="scanme.nmap.org  or  192.168.1.100"
              className="flex-1 bg-white/[0.04] border border-white/[0.08] rounded-lg px-3 py-2.5
                         font-mono text-[12px] text-slate-200 outline-none focus:border-accent/30
                         transition-colors placeholder-slate-700" />
            <button onClick={startScan} disabled={scanning}
              className="px-6 py-2.5 rounded-lg border border-accent/35 bg-accent/10 text-accent
                         font-mono text-[12px] font-bold hover:bg-accent/20 transition-all disabled:opacity-50">
              {scanning ? '⟳ SCANNING...' : '▶ SCAN'}
            </button>
          </div>
        </div>
        <div>
          <label className="font-mono text-[9px] uppercase tracking-widest text-slate-600 block mb-1.5">Goal</label>
          <select value={goal} onChange={e=>setGoal(e.target.value)}
            className="w-full bg-white/[0.04] border border-white/[0.08] rounded-lg px-3 py-2.5
                       font-mono text-[11px] text-slate-300 outline-none focus:border-accent/30 transition-colors">
            {GOALS.map(g=><option key={g} value={g}>{g}</option>)}
          </select>
        </div>
        {error && <div className="font-mono text-[11px] text-red-400 px-3 py-2 rounded border border-red-500/25 bg-red-500/8">✗ {error}</div>}
      </div>

      {/* Live status */}
      {processId && (
        <div className="grid grid-cols-[260px_1fr] gap-4">
          <div className="glass p-4 space-y-3 h-fit">
            <div className="font-mono text-[9px] text-slate-600 uppercase tracking-widest">Status</div>
            <div className="font-mono text-[9px] text-slate-600">Process ID</div>
            <div className="font-mono text-[10px] text-accent break-all">{processId}</div>
            {status && <>
              <div className={`font-mono text-[13px] font-bold uppercase ${
                status.status==='completed'?'text-accent':status.status==='failed'?'text-red-400':'text-yellow-400'}`}>
                {status.status}
              </div>
              {status.progress!=null && (
                <div>
                  <div className="flex justify-between font-mono text-[9px] text-slate-600 mb-1">
                    <span>Progress</span><span>{Math.round(status.progress)}%</span>
                  </div>
                  <div className="h-1.5 bg-white/[0.06] rounded overflow-hidden">
                    <div className="h-full bg-accent rounded transition-all" style={{width:`${status.progress}%`}}/>
                  </div>
                </div>
              )}
              {status.completed_tasks!=null && (
                <div className="font-mono text-[10px] text-slate-400">
                  Tasks: {status.completed_tasks}/{status.total_tasks}
                </div>
              )}
              {status.status==='completed' && (
                <a href={`/scanner/${processId}`}
                  className="block text-center font-mono text-[11px] py-2 rounded border border-accent/35 bg-accent/10 text-accent hover:bg-accent/20 transition-all">
                  VIEW REPORT →
                </a>
              )}
            </>}
          </div>
          <div className="glass overflow-hidden">
            <div className="flex items-center gap-2 px-4 py-3 border-b border-white/[0.06]">
              <div className={`w-2 h-2 rounded-full ${scanning?'bg-accent animate-pulse':'bg-slate-600'}`}/>
              <span className="font-mono text-[11px] text-accent uppercase tracking-widest">Live Output</span>
            </div>
            <div ref={logRef} className="font-mono text-[11px] p-4 overflow-y-auto space-y-0.5" style={{height:'300px',scrollbarWidth:'thin'}}>
              {logs.length===0
                ? <div className="text-slate-600 animate-pulse">Waiting for output...</div>
                : logs.map((l,i)=>(
                    <div key={i} className={l.includes('error')||l.includes('failed')?'text-red-400':l.includes('finding')||l.includes('✅')?'text-accent':'text-slate-400'}>
                      {l}
                    </div>
                  ))
              }
            </div>
          </div>
        </div>
      )}

      {/* History */}
      {history.length > 0 && (
        <div className="glass overflow-hidden">
          <div className="px-4 py-3 border-b border-white/[0.06]">
            <span className="font-mono text-[11px] text-accent uppercase tracking-widest">Recent Scans</span>
          </div>
          <table className="w-full border-collapse">
            <thead>
              <tr style={{background:'rgba(255,255,255,0.02)',borderBottom:'1px solid rgba(255,255,255,0.06)'}}>
                {['Process ID','Target','Status','Risk','Findings'].map(h=>(
                  <th key={h} className="font-mono text-[9px] text-slate-600 uppercase text-left px-4 py-2.5">{h}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {history.map((s:any)=>(
                <tr key={s.process_id}
                  className="border-b border-white/[0.03] hover:bg-white/[0.02] cursor-pointer transition-colors"
                  onClick={()=>{setProcessId(s.process_id);setStatus(s)}}>
                  <td className="px-4 py-2.5 font-mono text-[10px] text-accent2">{s.process_id}</td>
                  <td className="px-4 py-2.5 font-mono text-[11px] text-slate-300">{s.target??'—'}</td>
                  <td className="px-4 py-2.5 font-mono text-[10px] text-slate-400 capitalize">{s.status}</td>
                  <td className="px-4 py-2.5">
                    {s.risk_level&&<span className="font-mono text-[10px] font-bold uppercase" style={{color:RISK_COLOR[s.risk_level]??'#64748b'}}>{s.risk_level}</span>}
                  </td>
                  <td className="px-4 py-2.5 font-mono text-[11px] text-slate-400">{s.findings_count??'—'}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  )
}